 25→interface UploadFlags {
 26→	tag?: SessionTag;
 27→	endpoint: string;
 28→	classify: boolean;
 29→	dryRun: boolean;
 30→	org?: string;
 31→}
 32→
 33→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
 34→	const credentials = loadCredentials();
 35→	if (!credentials && !flags.dryRun) {
 36→		p.log.error("Not authenticated. Run `rudel login` first.");
 37→		process.exitCode = 1;
 38→		return;
 39→	}
 40→
 41→	p.intro("rudel upload");
 42→
 43→	const spin = p.spinner();
 44→	spin.start("Scanning projects...");
 45→	const projects = await scanProjects();
 46→	spin.stop(`Found ${projects.length} project(s)`);
 47→
 48→	if (projects.length === 0) {
 49→		p.log.warn("No projects with sessions found in ~/.claude/projects/");
 50→		p.outro("Nothing to upload.");
 51→		return;
 52→	}
 53→
 54→	const cwd = process.cwd();
 55→	const grouped = groupProjectsForCwd(projects, cwd);
 56→
 57→	const options: Array<{
 58→		value: ScannedProject;
 59→		label: string;
 60→		hint: string;
 61→	}> = [];
 62→	const preSelected: ScannedProject[] = [];
 63→
 64→	if (grouped.current) {
 65→		options.push({
 66→			value: grouped.current,
 67→			label: grouped.current.displayPath,
 68→			hint: sessionCountHint(grouped.current.sessionCount),
 69→		});
 70→		preSelected.push(grouped.current);
 71→
 72→		for (const sub of grouped.subfolders) {
 73→			const relative = sub.decodedPath.slice(
 74→				grouped.current.decodedPath.length + 1,
 75→			);
 76→			options.push({
 77→				value: sub,
 78→				label: `  ${relative}`,
 79→				hint: sessionCountHint(sub.sessionCount),
 80→			});
 81→			preSelected.push(sub);
 82→		}
 83→	}
 84→
 85→	for (const other of grouped.others) {
 86→		options.push({
 87→			value: other,
 88→			label: other.displayPath,
 89→			hint: sessionCountHint(other.sessionCount),
 90→		});
 91→	}
 92→
 93→	const selected = await p.multiselect({
 94→		message: "Select projects to upload",
 95→		options,
 96→		initialValues: preSelected,
 97→		required: true,
 98→	});
 99→
100→	if (p.isCancel(selected)) {
101→		p.cancel("Upload cancelled.");
102→		return;
103→	}
104→
105→	const totalSessions = selected.reduce(
106→		(sum, proj) => sum + proj.sessionCount,
107→		0,
108→	);
109→	p.log.info(
110→		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
111→	);
112→
113→	const batchOpts: BatchOptions = {
114→		tag: flags.tag,
115→		classify: flags.classify,
116→		dryRun: flags.dryRun,
117→		org: flags.org,
118→		uploadConfig: {
119→			endpoint: flags.endpoint,
120→			token: credentials?.token ?? "",
121→		},
122→	};
123→
124→	const uploadSpin = p.spinner();
125→	uploadSpin.start("Uploading sessions...");
126→
127→	const result = await batchUpload(selected, batchOpts, (current, total) => {
128→		uploadSpin.message(`[${current}/${total}] Uploading...`);
129→	});
130→
131→	uploadSpin.stop("Upload complete");
132→
133→	if (result.succeeded > 0) {
134→		p.log.success(`${result.succeeded} session(s) uploaded successfully`);
135→	}
136→	if (result.failed > 0) {
137→		p.log.error(`${result.failed} session(s) failed`);
138→		for (const err of result.errors.slice(0, 5)) {
139→			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
140→		}
141→		if (result.errors.length > 5) {
142→			p.log.warn(`  ...and ${result.errors.length - 5} more`);
143→		}
144→	}
145→
146→	if (flags.dryRun) {
147→		p.outro("Dry run complete — no sessions were uploaded.");
148→	} else {
149→		p.outro("Done!");
150→	}
151→
152→	if (result.failed > 0) {
153→		process.exitCode = 1;
154→	}
155→}
