 1→import { readdir } from "node:fs/promises";
 2→import { homedir } from "node:os";
 3→import { join } from "node:path";
 4→import {
 5→	addHook,
 6→	getClaudeSettingsPath,
 7→	isHookEnabled,
 8→	removeHook,
 9→} from "../claude-settings.js";
10→import { decodeProjectPath } from "../session-resolver.js";
11→import type { CodingAgent, SessionFile } from "./types.js";
12→
13→const SESSIONS_BASE_DIR = join(homedir(), ".claude", "projects");
14→
15→function encodeProjectPath(projectPath: string): string {
16→	return projectPath.replace(/\//g, "-");
17→}
18→
19→export class ClaudeCodeAgent implements CodingAgent {
20→	name = "Claude Code";
21→
22→	installHook(): void {
23→		addHook();
24→	}
25→
26→	removeHook(): void {
27→		removeHook();
28→	}
29→
30→	isHookInstalled(): boolean {
31→		return isHookEnabled();
32→	}
33→
34→	getHookSettingsPath(): string {
35→		return getClaudeSettingsPath();
36→	}
37→
38→	getSessionsBaseDir(): string {
39→		return SESSIONS_BASE_DIR;
40→	}
41→
42→	async findProjectSessions(projectPath: string): Promise<SessionFile[]> {
43→		const encoded = encodeProjectPath(projectPath);
44→		const sessionDir = join(SESSIONS_BASE_DIR, encoded);
45→
46→		const files = await this.listSessionFiles(sessionDir, projectPath);
47→		if (files.length > 0) return files;
48→
49→		// Fallback: iterate all project dirs and decode to find matches
50→		return this.findByDecoding(projectPath);
51→	}
52→
53→	private async listSessionFiles(
54→		sessionDir: string,
55→		projectPath: string,
56→	): Promise<SessionFile[]> {
57→		try {
58→			const entries = await readdir(sessionDir);
59→			return entries
60→				.filter((f) => f.endsWith(".jsonl") && !f.startsWith("agent-"))
61→				.map((f) => ({
62→					sessionId: f.replace(/\.jsonl$/, ""),
63→					transcriptPath: join(sessionDir, f),
64→					projectPath,
65→				}));
66→		} catch {
67→			return [];
68→		}
69→	}
70→
71→	private async findByDecoding(projectPath: string): Promise<SessionFile[]> {
72→		let projectDirs: string[];
73→		try {
74→			projectDirs = await readdir(SESSIONS_BASE_DIR);
75→		} catch {
76→			return [];
77→		}
78→
79→		for (const dir of projectDirs) {
80→			try {
81→				const decoded = await decodeProjectPath(dir);
82→				if (decoded === projectPath) {
83→					const sessionDir = join(SESSIONS_BASE_DIR, dir);
84→					return this.listSessionFiles(sessionDir, projectPath);
85→				}
86→			} catch {
87→				// skip undecodable dirs
88→			}
89→		}
90→
91→		return [];
92→	}
93→}
