20→export type AuthResult = AuthSuccess | AuthFailure;
21→
22→export async function verifyAuth(): Promise<AuthResult> {
23→	const credentials = loadCredentials();
24→	if (!credentials) {
25→		return {
26→			authenticated: false,
27→			reason: "no_credentials",
28→			message: "Not authenticated. Run `rudel login` first.",
29→		};
30→	}
31→
32→	const client = createApiClient(credentials);
33→	try {
34→		const user = await client.me();
35→		return { authenticated: true, credentials, user };
36→	} catch (error) {
37→		const message = String(error);
38→		const isAuthError =
39→			message.includes("401") ||
40→			message.includes("403") ||
41→			message.includes("Unauthorized") ||
42→			message.includes("Forbidden");
43→
44→		if (isAuthError) {
45→			clearCredentials();
46→			return {
47→				authenticated: false,
48→				reason: "token_expired",
49→				message:
50→					"Session expired or invalid. Run `rudel login` to re-authenticate.",
51→			};
52→		}
53→
54→		return {
55→			authenticated: false,
56→			reason: "network_error",
57→			message: "Failed to verify authentication. Check your connection.",
58→		};
59→	}
