39→async function getProjectKey(cwd: string): Promise<string> {
40→	// Prefer git remote URL (portable across clones)
41→	try {
42→		const result = await $`git -C ${cwd} remote get-url origin`.quiet();
43→		if (result.exitCode === 0) {
44→			const url = result.text().trim();
45→			// Normalize: strip .git suffix and protocol
46→			return url
47→				.replace(/^(https?:\/\/|git@|ssh:\/\/)/, "")
48→				.replace(/:/, "/")
49→				.replace(/\.git$/, "");
50→		}
51→	} catch {
52→		// Not a git repo or no remote
53→	}
54→
55→	// Fall back to absolute path
56→	try {
57→		const result = await $`git -C ${cwd} rev-parse --show-toplevel`.quiet();
58→		if (result.exitCode === 0) {
59→			return result.text().trim();
60→		}
61→	} catch {
62→		// Not a git repo
63→	}
64→
65→	return cwd;
66→}
