  1→import { dirname } from "node:path";
  2→import * as p from "@clack/prompts";
  3→import { buildCommand } from "@stricli/core";
  4→import { getDefaultAgent } from "../lib/agents/index.js";
  5→import { createApiClient } from "../lib/api-client.js";
  6→import { verifyAuth } from "../lib/auth.js";
  7→import { getGitInfo } from "../lib/git-info.js";
  8→import { getProjectOrgId, setProjectOrgId } from "../lib/project-config.js";
  9→import { readSubagentFiles } from "../lib/subagent-reader.js";
 10→import { extractAgentIds, readTranscript } from "../lib/transcript-reader.js";
 11→import type { IngestRequest } from "../lib/types.js";
 12→import { uploadSession } from "../lib/uploader.js";
 13→
 14→async function runEnable(): Promise<void> {
 15→	p.intro("rudel enable");
 16→
 17→	// Verify auth (loads credentials + pings API)
 18→	const auth = await verifyAuth();
 19→	if (!auth.authenticated) {
 20→		p.log.error(auth.message);
 21→		p.outro("Run `rudel login` to authenticate.");
 22→		process.exitCode = 1;
 23→		return;
 24→	}
 25→
 26→	const { credentials } = auth;
 27→
 28→	// Fetch user's organizations
 29→	const client = createApiClient(credentials);
 30→	let orgs: { id: string; name: string; slug: string }[];
 31→	try {
 32→		orgs = await client.listMyOrganizations();
 33→	} catch {
 34→		p.log.error("Failed to fetch organizations. Check your connection.");
 35→		process.exitCode = 1;
 36→		return;
 37→	}
 38→
 39→	if (orgs.length === 0) {
 40→		p.log.error("No organizations found.");
 41→		p.outro("Create one at app.rudel.ai first.");
 42→		process.exitCode = 1;
 43→		return;
 44→	}
 45→
 46→	// Check if already configured for this project
 47→	const cwd = process.cwd();
 48→	const existingOrgId = await getProjectOrgId(cwd);
 49→	const existingOrg = existingOrgId
 50→		? orgs.find((o) => o.id === existingOrgId)
 51→		: undefined;
 52→
 53→	let selectedOrgId: string;
 54→
 55→	const [firstOrg] = orgs;
 56→	if (orgs.length === 1 && firstOrg) {
 57→		selectedOrgId = firstOrg.id;
 58→		p.log.info(`Using organization: ${firstOrg.name}`);
 59→	} else if (existingOrg) {
 60→		p.log.info(`Currently configured for: ${existingOrg.name}`);
 61→		selectedOrgId = existingOrg.id;
 62→	} else {
 63→		const selected = await p.select({
 64→			message: "Select an organization for this repository",
 65→			options: orgs.map((org) => ({
 66→				value: org.id,
 67→				label: org.name,
 68→				hint: org.slug,
 69→			})),
 70→		});
 71→
 72→		if (p.isCancel(selected)) {
 73→			p.cancel("Setup cancelled.");
 74→			return;
 75→		}
 76→
 77→		selectedOrgId = selected;
 78→		const selectedOrg = orgs.find((o) => o.id === selected);
 79→		if (selectedOrg) {
 80→			p.log.success(`Selected: ${selectedOrg.name}`);
 81→		}
 82→	}
 83→
 84→	await setProjectOrgId(cwd, selectedOrgId);
 85→
 86→	// Install hook via agent abstraction
 87→	const agent = getDefaultAgent();
 88→
 89→	if (agent.isHookInstalled()) {
 90→		p.log.info("Auto-upload hook is already enabled. Organization updated.");
 91→	} else {
 92→		agent.installHook();
 93→		p.log.success(`Auto-upload hook enabled in ${agent.getHookSettingsPath()}`);
 94→	}
 95→
 96→	// Check for existing sessions to upload
 97→	const sessions = await agent.findProjectSessions(cwd);
 98→	if (sessions.length === 0) {
 99→		p.outro("Done!");
100→		return;
101→	}
102→
103→	const shouldUpload = await p.confirm({
104→		message: `Found ${sessions.length} previous session(s). Upload them now?`,
105→		initialValue: false,
106→	});
107→
108→	if (p.isCancel(shouldUpload) || !shouldUpload) {
109→		p.outro("Done!");
110→		return;
111→	}
112→
113→	const endpoint = `${credentials.apiBaseUrl}/rpc`;
114→	const spin = p.spinner();
115→	spin.start("Uploading sessions...");
116→
117→	let succeeded = 0;
118→	let failed = 0;
119→
120→	for (const [i, session] of sessions.entries()) {
121→		spin.message(`[${i + 1}/${sessions.length}] Uploading...`);
122→		try {
123→			const content = await readTranscript(session.transcriptPath);
124→			const agentIds = extractAgentIds(content);
125→			const sessionDir = dirname(session.transcriptPath);
126→			const subagents =
127→				agentIds.length > 0
128→					? await readSubagentFiles(sessionDir, agentIds, session.sessionId)
129→					: [];
130→			const gitInfo = await getGitInfo(session.projectPath);
131→
132→			const request: IngestRequest = {
133→				sessionId: session.sessionId,
134→				projectPath: session.projectPath,
135→				repository: gitInfo.repository,
136→				gitBranch: gitInfo.branch,
137→				gitSha: gitInfo.sha,
138→				content,
139→				subagents: subagents.length > 0 ? subagents : undefined,
140→				organizationId: selectedOrgId,
141→			};
142→
143→			const result = await uploadSession(request, {
144→				endpoint,
145→				token: credentials.token,
146→			});
147→
148→			if (result.success) {
149→				succeeded++;
150→			} else {
151→				failed++;
152→			}
153→		} catch {
154→			failed++;
155→		}
156→	}
157→
158→	spin.stop("Upload complete");
159→
160→	if (succeeded > 0) {
161→		p.log.success(`${succeeded} session(s) uploaded successfully`);
162→	}
163→	if (failed > 0) {
164→		p.log.error(`${failed} session(s) failed`);
165→	}
166→
167→	p.outro("Done!");
168→}
169→
170→export const enableCommand = buildCommand({
171→	loader: async () => ({ default: runEnable }),
172→	parameters: {},
173→	docs: {
174→		brief: "Enable automatic session upload via Claude Code hook",
175→	},
176→});
